import { useEffect } from "react";
import axios from "axios";

function Portfolio() {
  useEffect(() => {
    axios.post("http://localhost:5000/api/analytics/visit", {
      page: "portfolio",
      browser: navigator.userAgent,
    });

    const copyHandler = () => {
      axios.post("http://localhost:5000/api/analytics/copy");
    };

    document.addEventListener("copy", copyHandler);

    return () => {
      document.removeEventListener("copy", copyHandler);
    };
  }, []);

  const projectClick = async (name) => {
    await axios.post("http://localhost:5000/api/analytics/project", {
      project: name,
    });
  };

  const resumeDownload = async () => {
    await axios.post("http://localhost:5000/api/analytics/resume");
  };

  return (
    <div className="container">
      <h1>Nisha Yadav</h1>

      <h2>Projects</h2>

      <button onClick={() => projectClick("AI Virtual Mouse")}>
        AI Virtual Mouse
      </button>

      <button onClick={() => projectClick("AI Wardrobe")}>AI Wardrobe</button>

      <button onClick={() => projectClick("Travel Booking App")}>
        Travel Booking App
      </button>

      <br />
      <br />

      <a href="/resume.pdf" download onClick={resumeDownload}>
        Download Resume
      </a>
    </div>
  );
}

export default Portfolio;
